import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function DriverRoute() {
  const { id } = useParams();

  const navigate = useNavigate();

  const [task, setTask] = useState(null);

  const getTask = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/driver/today-task"
      );

      const found = res.data.requests.find(
        (item) => item._id === id
      );

      setTask(found);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTask();
  }, []);

  const markArrived = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/arrived/${id}`
      );

      setTask(res.data.data);
    } catch (error) {
      console.log(error);
    }
  };

const markCompleted = async () => {
  try {
    const res = await axios.put(
      `http://localhost:3000/api/driver/completed/${id}`
    );

    setTask(res.data.data);

    setTimeout(() => {
      navigate("/driver-dashboard");
    }, 2000);

  } catch (error) {
    console.log(error);
  }
};

  if (!task) {
    return (
      <div className="min-h-screen flex justify-center items-center">
        Loading...
      </div>
    );
  }

return (

    
  <div className="min-h-screen bg-[#4CBB17]/10">

    <div className="bg-green-700 text-white py-4 px-6 shadow">
      <h2 className="text-lg md:text-xl font-bold text-center">
        🚛 MANIT Bhopal → {task.location?.location}
      </h2>
    </div>

    <div className="flex flex-col items-center justify-center mt-24">

      {task.arrivedAt && (
        <div className="mb-4 bg-yellow-100 px-6 py-3 rounded-xl">
          <p className="font-semibold">
            Arrived Time
          </p>
          <p>
            {new Date(task.arrivedAt).toLocaleString()}
          </p>
        </div>
      )}

      {task.completedAt && (
        <div className="mb-4 bg-green-100 px-6 py-3 rounded-xl">
          <p className="font-semibold">
            Completed Time
          </p>
          <p>
            {new Date(task.completedAt).toLocaleString()}
          </p>
        </div>
      )}

      {task.status === "Scheduled" && (
        <button
          onClick={markArrived}
          className="bg-yellow-500 text-white px-12 py-4 rounded-xl text-xl font-bold"
        >
          Arrived
        </button>
      )}

      {task.status === "Arrived" && (
        <button
          onClick={markCompleted}
          className="bg-green-600 text-white px-12 py-4 rounded-xl text-xl font-bold"
        >
          Completed
        </button>
      )}

    </div>
  </div>
);
}
